import { getServerSession } from "next-auth";
import { authOptions } from "../lib/auth";
import { redirect } from "next/navigation";
import { prisma } from "../lib/prisma";
import SymptomsPieChart from "../components/SymptomsPieChart";
import HealthMonitor from "../components/HealthMonitor";
import SmartNotifier from "../components/SmartNotifier";

/**
 * หน้าวิเคราะห์ข้อมูลสุขภาพ (Health Analytics Dashboard)
 * ทำหน้าที่รวบรวมและวิเคราะห์สถิติจากบันทึกสุขภาพรายวัน
 */
export default async function DashboardPage() {
  const session = await getServerSession(authOptions);
  
  if (!session || !session.user?.email) {
    redirect("/login");
  }

  // กำหนดขอบเขตข้อมูลรายเดือน (Monthly Data Scope)
  const now = new Date();
  const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const lastDayOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

  // การดึงข้อมูลบันทึกสุขภาพจากฐานข้อมูลกลาง
  const records = await prisma.healthRecord.findMany({
    where: {
      author: { email: session.user.email },
      date: {
        gte: firstDayOfMonth,
        lte: lastDayOfMonth,
      },
    },
    orderBy: { date: 'desc' },
  });

  const totalRecords = records.length;
  
  // การประมวลผลข้อมูลอาการ (Symptom Data Processing)
  const symptomData = [
    { label: "ปวดคอ/บ่า", count: records.filter(r => r.neckPain).length },
    { label: "ปวดหลัง", count: records.filter(r => r.backPain).length },
    { label: "ปวดตา", count: records.filter(r => r.eyeStrain).length },
    { label: "ปวดข้อมือ", count: records.filter(r => r.wristPain).length },
    { label: "ปวดหัว", count: records.filter(r => r.headache).length },
    { label: "ชาปลายนิ้ว", count: records.filter(r => r.fingerNumbness).length },
    { label: "ชาที่ขา", count: records.filter(r => r.legNumbness).length },
  ];

  // คำนวณดัชนีชี้วัดสุขภาพหลัก (Key Performance Indicators)
  const stressAvg = totalRecords > 0 
    ? (records.reduce((acc, curr) => acc + curr.stressLevel, 0) / totalRecords).toFixed(1) 
    : "0.0";
  
  const stretchCount = records.filter(r => r.tookBreaks).length;
  const breakRatio = totalRecords > 0 ? stretchCount / totalRecords : 0;

  // ตรวจสอบภาวะเสี่ยงเร่งด่วน (7 วันย้อนหลัง)
  const recentRecords = records.slice(0, 7);
  const hasNumbness = recentRecords.some(r => r.fingerNumbness || r.legNumbness);

  const sortedSymptoms = [...symptomData].sort((a, b) => b.count - a.count);
  const topSymptom = sortedSymptoms[0];
  const hasSymptoms = topSymptom.count > 0;

  const totalSymptomTicks = symptomData.reduce((acc, curr) => acc + curr.count, 0);
  const avgSymptomsPerDay = totalRecords > 0 ? Math.ceil(totalSymptomTicks / totalRecords) : 0;

  return (
    <main style={containerStyle}>
      {/* ระบบแจ้งเตือนการปฏิบัติงาน (Operational Notification) */}
      <SmartNotifier />

      <header style={headerStyle}>
        <div>
          <h1 style={titleStyle}>ระบบวิเคราะห์สุขภาพ (Health Dashboard)</h1>
          <p style={subtitleStyle}>
            รายงานสรุปผลการวิเคราะห์ข้อมูลประจำเดือน <span style={{ fontWeight: '700', color: '#0ea5e9' }}>กุมภาพันธ์ 2026</span>
          </p>
        </div>
        <div style={userBadgeStyle}>
          <span style={userLabel}>ผู้ใช้งานระบบ:</span>
          <span style={userName}>{session.user.name || session.user.email}</span>
        </div>
      </header>

      <div style={dashboardGrid}>
        {/* ส่วนการประเมินสภาวะทางกายภาพและข้อเสนอแนะ */}
        <section style={leftSection}>
          <HealthMonitor 
            symptomsCount={avgSymptomsPerDay}
            hasNumbness={hasNumbness}
            breakRatio={breakRatio}
            topSymptom={hasSymptoms ? topSymptom.label : "ข้อมูลทั่วไป"}
          />
          
          <div style={metricsGrid}>
            <article style={{ ...metricCard, borderTop: '4px solid #ef4444' }}>
              <h3 style={metricLabel}>อาการที่ตรวจพบสูงสุด</h3>
              <p style={metricValue}>{hasSymptoms ? topSymptom.label : "ไม่พบรายการ"}</p>
              <footer style={metricFooter}>ความถี่สะสม: {hasSymptoms ? topSymptom.count : 0} ครั้ง</footer>
            </article>

            <article style={{ ...metricCard, borderTop: '4px solid #f59e0b' }}>
              <h3 style={metricLabel}>ค่าเฉลี่ยความเหนื่อยล้า</h3>
              <p style={metricValue}>{stressAvg} <span style={{ fontSize: '14px', color: '#94a3b8' }}>/ 5.0</span></p>
              <footer style={metricFooter}>สถานะ: {Number(stressAvg) > 3 ? "ควรเพิ่มเวลาพักผ่อน" : "อยู่ในเกณฑ์ปกติ"}</footer>
            </article>
          </div>
        </section>

        {/* ส่วนวิเคราะห์ทางสถิติในรูปแบบกราฟ */}
        <section style={rightSection}>
          <div style={chartCardStyle}>
            <header style={chartHeader}>
              <h3 style={chartTitle}>สัดส่วนการกระจายตัวของอาการ</h3>
              <p style={chartSubtitle}>ข้อมูลวิเคราะห์เชิงเปรียบเทียบในรอบเดือนปัจจุบัน</p>
            </header>
            <div style={chartContent}>
              <SymptomsPieChart data={symptomData} />
            </div>
          </div>
        </section>
      </div>
    </main>
  );
}

// --- การกำหนดรูปแบบการแสดงผลระดับ Enterprise ---
const containerStyle = { maxWidth: '1200px', margin: '0 auto', padding: '40px 24px 80px 24px' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' };
const titleStyle = { fontSize: '26px', fontWeight: '800', color: '#0f172a', margin: 0 };
const subtitleStyle = { fontSize: '15px', color: '#64748b', marginTop: '4px' };
const userBadgeStyle = { display: 'flex', flexDirection: 'column' as const, alignItems: 'flex-end' };
const userLabel = { fontSize: '11px', fontWeight: '700', color: '#94a3b8', textTransform: 'uppercase' as const };
const userName = { fontSize: '15px', fontWeight: '700', color: '#334155' };
const dashboardGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(480px, 1fr))', gap: '32px' };
const leftSection = { display: 'flex', flexDirection: 'column' as const, gap: '24px' };
const metricsGrid = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' };
const metricCard = { background: '#ffffff', padding: '24px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' };
const metricLabel = { margin: 0, fontSize: '12px', color: '#64748b', fontWeight: '700', textTransform: 'uppercase' as const, letterSpacing: '0.05em' };
const metricValue = { margin: '12px 0', fontSize: '24px', fontWeight: '800', color: '#1e293b' };
const metricFooter = { fontSize: '13px', color: '#94a3b8' };
const rightSection = { width: '100%' };
const chartCardStyle = { background: '#ffffff', padding: '32px', borderRadius: '20px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', border: '1px solid #e2e8f0' };
const chartHeader = { marginBottom: '24px', borderBottom: '1px solid #f1f5f9', paddingBottom: '16px' };
const chartTitle = { margin: 0, fontSize: '18px', fontWeight: '800', color: '#0f172a' };
const chartSubtitle = { margin: '4px 0 0 0', fontSize: '14px', color: '#64748b' };
const chartContent = { display: 'flex', justifyContent: 'center' };